namespace DocuGenious.Core.Configuration;

public class AppSettings
{
    public JiraSettings Jira { get; set; } = new();
    public GitSettings Git { get; set; } = new();
    public GroqSettings Groq { get; set; } = new();
    public GeminiSettings Gemini { get; set; } = new();
    public OutputSettings Output { get; set; } = new();
}

public class GeminiSettings
{
    public string ApiKey { get; set; } = string.Empty;
    public string Model { get; set; } = "gemini-2.5-flash";
    public int MaxOutputTokens { get; set; } = 8192;
    public int TimeoutSeconds { get; set; } = 300;
    public string BaseUrl { get; set; } = "https://generativelanguage.googleapis.com/v1beta";
    public GeminiTruncationSettings Truncation { get; set; } = new();
}

public class GeminiTruncationSettings
{
    public int JiraDescriptionMaxChars { get; set; } = 2000;
    public int JiraAcceptanceCriteriaMaxChars { get; set; } = 300;
    public int JiraCommentMaxChars { get; set; } = 300;
    public int GitCommitMessageMaxChars { get; set; } = 200;
    public int GitFileContentMaxChars { get; set; } = 2000;
    public int PromptMaxChars { get; set; } = 80000;
}

using DocuGenious.Api.Services;
using DocuGenious.Core.Interfaces;
using DocuGenious.Core.Models;
using Microsoft.AspNetCore.Mvc;

namespace DocuGenious.Api.Controllers;

[ApiController]
[Route("api/documentation")]
public class DocumentationController : ControllerBase
{
    private readonly IJiraService _jiraService;
    private readonly IGitService _gitService;
    private readonly IGeminiService _geminiService;
    private readonly IPdfService _pdfService;
    private readonly JobStatusService _jobStatus;

    [HttpPost("generate")]
    public async Task<IActionResult> GenerateDocumentation([FromBody] DocumentationRequest request)
    {
        var jobId = request.JobId;
        void Status(string msg) { if (!string.IsNullOrWhiteSpace(jobId)) _jobStatus.Update(jobId, msg); }

        Status("📋 Fetching Jira tickets…");
        // ... fetch, analyse, generate PDF
        return Ok(new { success = true, fileName = "output.pdf" });
    }

    [HttpGet("status/{jobId}")]
    public IActionResult GetStatus(string jobId)
    {
        var status = _jobStatus.Get(jobId);
        return status is null ? NoContent() : Ok(new { status });
    }
}

using DocuGenious.Core.Configuration;
using DocuGenious.Core.Interfaces;
using DocuGenious.Core.Models;
using Microsoft.Extensions.Options;

namespace DocuGenious.Integration.Gemini;

public class GeminiService : IGeminiService
{
    private readonly GeminiSettings _settings;
    private readonly HttpClient _http;

    public GeminiService(IOptions<AppSettings> options, HttpClient http)
    {
        _settings = options.Value.Gemini;
        _http = http;
    }

    private string BuildJiraContext(List<JiraTicket> tickets)
    {
        var t = _settings.Truncation;
        var sb = new StringBuilder();
        foreach (var ticket in tickets)
        {
            sb.AppendLine($"Key: {ticket.Key}");
            sb.AppendLine($"Summary: {ticket.Summary}");
            var desc = ticket.Description?.Length > t.JiraDescriptionMaxChars
                ? ticket.Description[..t.JiraDescriptionMaxChars] + "..."
                : ticket.Description;
            sb.AppendLine($"Description: {desc}");
        }
        return sb.ToString();
    }

    private string TruncateIfNeeded(string prompt)
    {
        var max = _settings.Truncation.PromptMaxChars;
        return prompt.Length > max ? prompt[..max] + "\n\n[Source data truncated]" : prompt;
    }
}

